#include <stdio.h>
#include <stdint.h>

int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    uint64_t arr[N];
    for (int i = 0; i < N; i++) {
        scanf("%llu", &arr[i]);
    }
    int count = 0;
    for (uint64_t mask = 1; mask < (1ULL << N); mask++) {
        uint64_t product = 1;
        for (int i = 0; i < N; i++) {
            if ((mask & (1ULL << i)) != 0) {
                product *= arr[i];
                if (product > K) break;
            }
        }
        if (product <= K) count++;
    }
    printf("%d\n", count);
    return 0;
}

